text:
{
  "formal_minutes": {
    "decisions": {
      "confirmed_decisions": [
        {
          "item": "테마 패키지 릴리스 목표는 수요일이 아니라 '금요일 15:00 KST'로 확정됨(단, 스모크 테스트 통과 시).",
          "justification": "회의에서 'Wednesday는 내부 stretch goal', 최종 목표는 금요일 15:00 KST로 합의됨."
        },
        {
          "item": "패키지명 불일치(packageName mismatch) 발생 시 스크립트를 무시하지 않고, 먼저 패키지 설정/계약 자체를 점검한 뒤 필요 시 스크립트만 검토한다.",
          "justification": "Hara 제안은 거부되었고, 최종 의사결정으로 반영됨."
        }
      ],
      "rejected_proposals": [
        {
          "item": "Hara의 'smoke-theme-pack.mjs에서 packageName 불일치 무시' 제안은 반려됨.",
          "reason": "계약/설정 검증이 우선되어야 한다는 합의가 있었음."
        },
        {
          "item": "릴리스 일정을 수요일 고정으로 확정(내부 stretch goal을 공식 일정으로 전환)하는 제안은 반려됨.",
          "reason": "스모크 테스트 통과를 선결 조건으로 두고 금요일 15:00 KST를 공식 목표로 확정함."
        }
      ],
      "non_decisions": [
        {
          "item": "README 설치 가이드 리뷰의 최종 책임자와 최종 기한은 미확정.",
          "notes": "Hara, Minjun, Doyun이 아니라 Seoyeon이 검토 희망을 제안했으나 미배정."
        },
        {
          "item": "릴리스 노트에 내부 수요일 stretch goal을 언급할지 여부 미결정.",
          "notes": "명시적 합의 없음."
        },
        {
          "item": "최종 릴리스 승인 권한자(approval authority)는 미정."
        }
      ],
      "risks": [
        {
          "item": "잘못된 tarball 경로 사용 가능성",
          "impact": "릴리스 지연 가능성"
        },
        {
          "item": "README 설치 단계가 오래되었을 경우",
          "impact": "릴리스 노트/문서가 사용자에게 오도된 정보 제공 가능성"
        },
        {
          "item": "주말 전후 타임라인에서는 스모크 결과 재확인 미비시 일정 신뢰도 저하 위험",
          "impact": "공개 릴리스 판단 지연"
        }
      ],
      "open_questions": [
        "최종 릴리스 승인 권한자는 누구인가?",
        "릴리스 노트에 내부 수요일 stretch goal을 기재할 것인지?",
        "README 검토를 누가, 어떤 기준으로 마무리할지?",
        "tarball 경로 확인 시점/방식의 구체적 기준은 누가 정리할지?"
      ]
    },
    "confirmed_and_internal": {
      "internal_stretch_goals": [
        {
          "item": "수요일 공개 준비 완료 목표",
          "type": "stretch_goal",
          "status": "내부 목표로만 운영, 공식 릴리스 목표 아님"
        }
      ]
    }
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과 공유",
      "due": "2026-05-15 10:00 KST",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 실패 원인 트리아지 노트를 action_items.md에 작성",
      "due": "2026-05-15 12:00 KST",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성 tarball 경로 확인",
      "due": "미정(결과 게시 후)",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 최신성 검토(가능하면 목요일에 검토)",
      "due": "목표: 2026-05-14(목) 가능하면",
      "status": "미확정",
      "source_certainty": "medium"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "금요일 10:00 KST 이전에 Minjun의 스모크 테스트 결과 공유가 완료되었는지 확인",
      "스모크 실패 시 Doyun의 트리아지 노트(action_items.md) 작성 완료 여부 확인",
      "Hara의 tarball 경로 확인이 진행되었는지, 경로 불일치 여부 점검",
      "README 리뷰가 지정 책임자 없이 누락되지 않도록 주책임자 배정 필요",
      "최종 릴리스 승인 권한자와 릴리스 노트 문구(내부 stretch goal 포함 여부) 결정"
    ],
    "what_not_to_invent": [
      "고객명/파트너명(명시되지 않음)",
      "예산 범위나 비용 수치",
      "보안 이슈, 장애/정전, 법무 승인, 소유자 추가 배정, 기타 마감 기한(명시되지 않은 시간)",
      "패키지명 불일치 스크립트 우회 허용(회차에서 반대된 제안)",
      "최종 승인권자 성립 여부나 책임자 대체 후보(근거 없는 추정)"
    ]
  },
  "non_invention_rules": [
    "회의 내역에서 직접 명시되지 않은 사실(고객명/예산/보안/장애/법무/소유자/마감일)을 생성하거나 추론해 채우지 않는다.",
    "raw notes에 없는 수치·일정·권한 구조를 임의로 부여하지 않는다.",
    "README 검토 미배정 상태와 미정 기한을 확정값으로 바꾸지 않는다.",
    "거부된 제안(예: packageName mismatch 무시)을 채택 사실로 오인 표기하지 않는다.",
    "리포트는 공개용 합성 데이터만 사용하고, 외부 사실이나 추측 기반 레퍼런스를 참조하지 않는다."
  ]
}
